  ('social-worker-moex-01501', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會工作師法第四章社會工作師事務所之相關規定，下列何者錯誤？', '["社會工作師事務所之社會工作師，須執行社會工作師法第12條規定之業務3年以上，並取得 工作證明者", "有2個以上社會工作師聯合申請設立者，以其中1人為負責社會工作師", "社會工作師事務所之收費標準，由直轄市及縣市主管機關核定之", "社會工作師事務所停業、歇業，應自事實發生之日起30日內，報請原發開業執照機關備查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
