  ('social-worker-moex-01503', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據性侵害犯罪防治法，下列何者不是直轄市、縣（市）主管機關設性侵害防治中心應辦理之 事項？', '["加害人之追蹤輔導及身心治療", "研擬性侵害防治政策及法規", "提供被害人24小時緊急救援", "協調醫院成立專門處理性侵害事件之醫療小組"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01504', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於心智障礙者之性侵被害人在偵查或審判階段的敘述，下列何者正確？', '["可以由家長協助詢問", "可以由配偶協助詢問", "可以由具相關專業人士協助詢問", "可以由法定代理人協助詢問"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01505', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據精神衛生法，有關精神醫療照護業務的相關規定，下列敘述何者錯誤？', '["精神醫療機構診治病人或於病人住院時，應向其本人及其保護人說明病情、治療方針等有關事項", "精神照護機構為保護病人安全，經告知病人後，得限制其活動之區域範圍", "精神醫療機構為醫療之目的或為防範緊急暴力意外、自殺或自傷之事件，得拘束病人身體於特 定之保護設施內", "經緊急安置或強制住院之嚴重病人或其保護人，不得向法院聲請裁定停止緊急安置或強制住院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01506', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者不屬於性別工作平等法的家庭照顧假規範？', '["受僱者於其家庭成員預防接種時，得請家庭照顧假", "受僱者請家庭照顧假時，雇主得視工作狀況決定是否拒絕", "受僱者請家庭照顧假時，雇主不得視為缺勤影響其全勤獎金", "受僱者於其家庭成員發生嚴重疾病時，得請家庭照顧假"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01507', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關志願服務法條文內容的敘述，下列何者錯誤？', '["志願服務運用單位應為志工辦理意外事故保險", "志願服務運用單位對於參與服務成績良好之志工，因升學、進修、就業或其他原因需志願服務 績效證明者，得發給服務績效證明書", "志願服務運用單位應定期考核志工個人及團隊之服務績效", "志工服務年資滿2年，服務時數達200小時以上者，得檢具證明文件向地方主管機關申請核發 志願服務榮譽卡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01508', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據國民年金法，關於國民年金保險保險費之計算與保險給付的規定，下列敘述何者錯誤？', '["同一種保險給付，得因同一保險事故，重複請領", "被保險人、受益人或其他利害關係人，故意造成保險事故者，除喪葬給付外，保險人不予保險 給付", "被保險人應負擔之保險費於繳納後，不予退還。但非可歸責於被保險人之事由所溢繳或誤繳 者，不在此限", "被保險人得申請減領保險給付；其申請，1年以1次為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
