  ('social-worker-moex-01510', 'social-worker', 'social-worker-moex-109-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據長期照顧服務機構法人條例，有關長照機構法人之規定，下列敘述何者錯誤？', '["長照機構法人之董事會，每半年至少開會1次，由董事長召集之", "長照機構法人經主管機關許可，除設立長照機構外，並得設立社會福利機構或提供經中央主管 機關公告之服務", "長照機構法人應有足以達成其設立目的所必要之財產", "長照機構法人得投資衍生性金融商品"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "1d6fd40cd1db", "answer_pdf_sha1": "e585d4ce7c7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
